const r="./api",i={async getConnectors(){const n=await fetch(`${r}/connectors`);if(!n.ok)throw new Error("Fehler beim Laden der Connectoren");return n.json()},async testConnection(n,e,o,t){const s=await fetch(`${r}/connectors/test`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({connector_id:n,host:e,username:o,password:t})});if(!s.ok){const a=await s.json();throw new Error(a.detail||"Verbindungstest fehlgeschlagen")}return s.json()},async setup(n,e,o,t,s){const a=await fetch(`${r}/connectors/setup/${n}`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({connector_id:e,host:o,username:t,password:s})});if(!a.ok){const c=await a.json();throw new Error(c.detail||"Einrichtung fehlgeschlagen")}return a.json()},async getStatus(n){const e=await fetch(`${r}/connectors/status/${n}`);if(!e.ok)throw new Error("Fehler beim Laden des Connector-Status");return e.json()},async fetch(n){const e=await fetch(`${r}/connectors/fetch/${n}`,{method:"POST"});if(!e.ok){const o=await e.json();throw new Error(o.detail||"Ablesung fehlgeschlagen")}return e.json()},async saveMapping(n,e){const o=await fetch(`${r}/connectors/mapping/${n}`,{method:"PUT",headers:{"Content-Type":"application/json"},body:JSON.stringify({field_inv_map:e})});if(!o.ok){const t=await o.json();throw new Error(t.detail||"Zuordnung fehlgeschlagen")}return o.json()},async remove(n){const e=await fetch(`${r}/connectors/${n}`,{method:"DELETE"});if(!e.ok){const o=await e.json();throw new Error(o.detail||"Entfernen fehlgeschlagen")}},async getMonatswerte(n,e,o){const t=await fetch(`${r}/connectors/monatswerte/${n}/${e}/${o}`);if(!t.ok){const s=await t.json();throw new Error(s.detail||"Keine Connector-Daten für diesen Monat")}return t.json()}};export{i as c};
